nodes.notes:
Google Calendar — view, create, update, or delete events.

Actions:
  get — list events in a date range. Use for "what's on my calendar", "any meetings today", "schedule this week".
  create — create a new event. Use for "add a meeting", "schedule lunch", "book time for".
  update — modify an existing event. Requires event_id from a prior get call. Only include fields you want to change.
  delete — remove an event by ID. Requires event_id from a prior get call.

Rules:
- Dates are YYYY-MM-DD format. end_date is exclusive — to get one day, use start_date=today, end_date=tomorrow.
- Times are HH:MM in 24hr format.
- event_id comes from a prior get call. Do not fabricate event IDs.
- For update, only send fields that should change. Omitted fields remain unchanged.

---schema
{
  "action": {
    "type": "string",
    "description": "One of: get, create, update, delete",
    "required": true
  },
  "start_date": {
    "type": "string",
    "description": "Start date YYYY-MM-DD. For: get"
  },
  "end_date": {
    "type": "string",
    "description": "End date YYYY-MM-DD, exclusive. For: get"
  },
  "title": {
    "type": "string",
    "description": "Event title. For: create, update"
  },
  "date": {
    "type": "string",
    "description": "Event date YYYY-MM-DD. For: create, update"
  },
  "start_time": {
    "type": "string",
    "description": "Start time HH:MM 24hr, e.g. 14:30. For: create, update"
  },
  "end_time": {
    "type": "string",
    "description": "End time HH:MM 24hr. For: create, update"
  },
  "description": {
    "type": "string",
    "description": "Event description. For: create, update"
  },
  "location": {
    "type": "string",
    "description": "Event location. For: create, update"
  },
  "event_id": {
    "type": "string",
    "description": "Event ID from a prior get call. For: update, delete"
  }
}

parameters.jsCode:
const body = $input.item.json.body || {};

let data;
if (typeof body === 'string') {
  data = JSON.parse(body);
} else if (typeof body === 'object') {
  data = body;
} else {
  data = $input.item.json;
}

const action = (data.action || 'get').toLowerCase();

// Get action params
const start_date = data.start_date || null;
const end_date = data.end_date || null;

// Create action params
const title = data.title || data.summary || null;
const date = data.date || null;
const start_time = data.start_time || null;
const end_time = data.end_time || null;
const description = data.description || '';
const location = data.location || '';

// Delete action params
const event_id = data.event_id || data.id || null;

// Build datetime for create
let startDateTime = null;
let endDateTime = null;
let isAllDay = false;

if (action === 'create' && date) {
  if (start_time) {
    startDateTime = date + 'T' + start_time + ':00';
    if (end_time) {
      endDateTime = date + 'T' + end_time + ':00';
    } else {
      // Default 1 hour duration
      const [h, m] = start_time.split(':').map(Number);
      const endH = String(h + 1).padStart(2, '0');
      endDateTime = date + 'T' + endH + ':' + String(m).padStart(2, '0') + ':00';
    }
  } else {
    isAllDay = true;
  }
}

return [{ json: {
  action,
  start_date,
  end_date,
  title,
  date,
  startDateTime,
  endDateTime,
  isAllDay,
  description,
  location,
  event_id
}}];

function utcToLocal(utcString, timeZone) {
  if (!utcString) return '';
  const date = new Date(utcString);
  const options = {
    timeZone: timeZone,
    hour: 'numeric',
    minute: '2-digit',
    hour12: true
  };
  return new Intl.DateTimeFormat('en-US', options).format(date);
}

const events = items.map(item => {
  const startObj = item.json.start;
  const endObj = item.json.end;
  const tz = startObj?.timeZone || 'America/Vancouver';

  let startTime = '';
  let endTime = '';
  let isAllDay = false;

  if (startObj?.dateTime) {
    startTime = utcToLocal(startObj.dateTime, tz);
    endTime = utcToLocal(endObj?.dateTime, tz);
  } else if (startObj?.date) {
    isAllDay = true;
    startTime = 'all day';
  }

  return {
    id: item.json.id,
    title: item.json.summary || 'Untitled Event',
    time: startTime,
    endTime: endTime,
    isAllDay: isAllDay,
    location: item.json.location || '',
    description: item.json.description || ''
  };
});

let message = '';
if (events.length === 0) {
  message = 'You have no events scheduled.';
} else if (events.length === 1) {
  const e = events[0];
  if (e.isAllDay) {
    message = `You have one event: ${e.title}, all day.`;
  } else {
    message = `You have one event: ${e.title} at ${e.time}.`;
  }
} else {
  message = `You have ${events.length} events. `;
  const topEvents = events.slice(0, 5);
  const summaries = topEvents.map(e => {
    if (e.isAllDay) return `${e.title}, all day`;
    return `${e.title} at ${e.time}`;
  });
  message += summaries.join('. ') + '.';
  if (events.length > 5) {
    message += ` Plus ${events.length - 5} more.`;
  }
}

return [{ json: { message, action: 'get', events } }];

const event = $input.item.json;
const params = $('Parse Parameters').item.json;
const title = params.title || event.summary || 'the event';

let message = '';
if (params.isAllDay) {
  const d = new Date(params.date + 'T12:00:00');
  const formatted = d.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });
  message = `Done. Added ${title} on ${formatted}, all day.`;
} else {
  const start = new Date(params.startDateTime);
  const time = start.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
  const date = start.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });
  message = `Done. Added ${title} on ${date} at ${time}.`;
}

return { message, action: 'create', event: { id: event.id, title: event.summary } };

const event = $input.item.json;
const params = $('Parse Parameters').item.json;

const changes = [];
if (params.title) changes.push('title');
if (params.date || params.start_time) changes.push('time');
if (params.description) changes.push('description');
if (params.location) changes.push('location');

const title = event.summary || params.title || 'the event';
const what = changes.length > 0 ? changes.join(', ') : 'details';

return [{ json: { message: `Done. Updated ${what} for ${title}.`, action: 'update', event: { id: event.id, title: event.summary } } }];

const errorData = $input.item.json;
let errorMsg = errorData.message || errorData.error || 'Unknown error';
if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}
errorMsg = String(errorMsg);

if (errorMsg.includes('authorization') || errorMsg.includes('token') || errorMsg.includes('invalid_grant')) {
  errorMsg = 'Google Calendar authentication failed. Please re-authorize in n8n.';
} else if (errorMsg.includes('not found') || errorMsg.includes('404')) {
  errorMsg = 'Event not found. It may have been deleted.';
} else if (errorMsg.includes('Credential')) {
  errorMsg = 'Google Calendar credentials not found in n8n.';
}

return [{ json: { message: 'Error: ' + errorMsg, error: true } }];
